"use client";

import { FormEvent, useEffect, useState } from "react";

const API_BASE =
  process.env.NEXT_PUBLIC_API_BASE_URL || "http://localhost:4001";

type Me = {
  id: string;
  email: string;
  createdAt: string;
};

export default function AuthPage() {
  const [mode, setMode] = useState<"login" | "register">("login");

  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");

  const [token, setToken] = useState<string>("");
  const [me, setMe] = useState<Me | null>(null);

  const [err, setErr] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  const loadMe = async (t: string) => {
    const res = await fetch(`${API_BASE}/api/auth/me`, {
      headers: { Authorization: `Bearer ${t}` },
    });
    const data = await res.json().catch(() => null);
    if (!res.ok) throw new Error(data?.error || "Не удалось загрузить пользователя");
    return data as Me;
  };

  useEffect(() => {
    try {
      const t = localStorage.getItem("aevion_token") || "";
      if (!t) return;
      setToken(t);
      loadMe(t)
        .then((u) => setMe(u))
        .catch(() => {
          localStorage.removeItem("aevion_token");
          setToken("");
          setMe(null);
        });
    } catch {
      // Игнорируем ошибки localStorage.
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const submit = async (e: FormEvent) => {
    e.preventDefault();
    setErr(null);
    setLoading(true);
    try {
      if (!email.trim() || !password) {
        setErr("Email и пароль обязательны");
        return;
      }

      if (mode === "register") {
        const regRes = await fetch(`${API_BASE}/api/auth/register`, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ email, password }),
        });
        const regData = await regRes.json().catch(() => null);
        if (!regRes.ok) throw new Error(regData?.error || "Ошибка регистрации");

        // После регистрации сразу выполняем логин.
      }

      const loginRes = await fetch(`${API_BASE}/api/auth/login`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ email, password }),
      });
      const loginData = await loginRes.json().catch(() => null);
      if (!loginRes.ok) throw new Error(loginData?.error || "Ошибка входа");

      const t = loginData.token as string;
      localStorage.setItem("aevion_token", t);
      setToken(t);
      const u = await loadMe(t);
      setMe(u);
    } catch (e: any) {
      setErr(e?.message || "Ошибка");
    } finally {
      setLoading(false);
    }
  };

  const logout = () => {
    try {
      localStorage.removeItem("aevion_token");
    } catch {
      // ignore
    }
    setToken("");
    setMe(null);
  };

  const title =
    mode === "login" ? "Вход в AEVION" : "Регистрация в AEVION";

  return (
    <main style={{ padding: 24, maxWidth: 900 }}>
      <h1 style={{ fontSize: 26, marginBottom: 6 }}>{title}</h1>
      <p style={{ color: "#666", marginTop: 0 }}>
        MVP: регистрация/логин и проверка текущего пользователя.
      </p>

      {err && <div style={{ color: "crimson", margin: "12px 0" }}>{err}</div>}

      <section
        style={{
          border: "1px solid #ddd",
          borderRadius: 10,
          padding: 14,
          marginTop: 18,
        }}
      >
        <div style={{ display: "flex", gap: 10, marginBottom: 12 }}>
          <button
            type="button"
            onClick={() => setMode("login")}
            style={{
              padding: "8px 12px",
              borderRadius: 8,
              border: "1px solid #ccc",
              background: mode === "login" ? "#111" : "#fff",
              color: mode === "login" ? "#fff" : "#111",
            }}
          >
            Логин
          </button>
          <button
            type="button"
            onClick={() => setMode("register")}
            style={{
              padding: "8px 12px",
              borderRadius: 8,
              border: "1px solid #ccc",
              background: mode === "register" ? "#0a5" : "#fff",
              color: mode === "register" ? "#fff" : "#0a5",
            }}
          >
            Регистрация
          </button>
        </div>

        <form onSubmit={submit} style={{ display: "grid", gap: 10 }}>
          <input
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            placeholder="Email"
            style={{ padding: 10, borderRadius: 8, border: "1px solid #ccc" }}
          />
          <input
            type="password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            placeholder="Пароль (min 8 символов)"
            style={{ padding: 10, borderRadius: 8, border: "1px solid #ccc" }}
          />

          <button
            type="submit"
            disabled={loading}
            style={{
              padding: 10,
              borderRadius: 8,
              border: "1px solid #111",
              background: "#111",
              color: "#fff",
            }}
          >
            {loading ? "Пожалуйста, подождите..." : mode === "login" ? "Войти" : "Зарегистрироваться"}
          </button>
        </form>
      </section>

      <section style={{ marginTop: 22 }}>
        <h2 style={{ fontSize: 18, marginBottom: 10 }}>Пользователь</h2>
        {me ? (
          <div
            style={{
              border: "1px solid #ddd",
              borderRadius: 10,
              padding: 14,
            }}
          >
            <div style={{ display: "flex", justifyContent: "space-between", gap: 12 }}>
              <div>
                <div style={{ fontWeight: 700 }}>{me.email}</div>
                <div style={{ color: "#666", fontSize: 12, marginTop: 6 }}>
                  joined: {new Date(me.createdAt).toLocaleString()}
                </div>
              </div>
              <button
                type="button"
                onClick={logout}
                style={{
                  height: 36,
                  padding: "0 14px",
                  borderRadius: 8,
                  border: "1px solid #ccc",
                  background: "#fff",
                  color: "#111",
                  cursor: "pointer",
                }}
              >
                Выйти
              </button>
            </div>
          </div>
        ) : (
          <div style={{ color: "#666" }}>
            Вы не залогинены.
          </div>
        )}
      </section>
    </main>
  );
}

